    function testZeroAddressTransfer() public {
        address payable zero = payable(address(0));
        // This will revert with a generic error in Solidity 0.8.20
        zero.transfer(1 ether);
    }
}

// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

contract BalanceCheckExample {
    function checkBalance(uint256 amount) external view returns (bool) {
        // This is the pattern used in the solution
        return address(this).balance < amount;
    }

    function checkBalanceAssembly(uint256 amount) external view returns (bool) {
        // Alternative using assembly (not recommended unless necessary)
        uint256 balance;
        assembly {
            balance := selfbalance()
        }
        return balance < amount;
    }
}
